import Chance from 'chance';
var chance = new Chance();
var chances = [
    chance.word,
    chance.sentence,
    chance.url,
    chance.birthday,
    chance.avatar,
    chance.address,
];
function makeRandomContent() {
    var index = chance.integer({ min: 0, max: (chances.length - 1) / 2 });
    return "" + chances[index].call(chance);
}
function makeRandomHTML() {
    return "<ul>" + Array.from({ length: 5 }).reduce(function (html) {
        return html +
            ("<li>" + Array.from({ length: 5 }).reduce(function (html) {
                return (html += "<span style=\"font-size: " + chance.integer({
                    min: 7,
                    max: 30,
                }) + "px;\">" + makeRandomContent()
                    .split('')
                    .slice(0, 10)
                    .join('') + "</span>");
            }, '') + "</li>");
    }, '') + "</ul>\n  " + Array.from({ length: 1 }).reduce(function (html) {
        return html +
            ("<p>" + Array.from({ length: 15 }).reduce(function (html) {
                var randomChanceContent = makeRandomContent().split('');
                while (randomChanceContent.length > 10) {
                    var offset = chance.integer({
                        min: 0,
                        max: (randomChanceContent.length - 1) / 2,
                    });
                    var fontSize = chance.integer({ min: 7, max: 30 });
                    var withAnchor = chance.integer({ min: 0, max: 10 }) === 1;
                    var content = "<span style=\"font-size: " + fontSize + "px;\">" + randomChanceContent
                        .splice(0, offset)
                        .join('') + "</span>";
                    if (withAnchor) {
                        content = "<a href=\"#\">" + content + "</a>";
                    }
                    html += content;
                }
                return html + randomChanceContent.join('');
            }, '') + "</p>");
    }, '');
}
export { makeRandomHTML };
